/**
 * @summary List appointment types (scoped by business or all published)
 */
export const getListAppointmentsUrl = (params?: ListAppointmentsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/appointments?${stringifiedParams}`
    : `/api/appointments`;
};

export const listAppointments = async (
  params?: ListAppointmentsParams,
  options?: RequestInit,
): Promise<AppointmentType[]> => {
  return customFetch<AppointmentType[]>(getListAppointmentsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListAppointmentsQueryKey = (
  params?: ListAppointmentsParams,
) => {
  return [`/api/appointments`, ...(params ? [params] : [])] as const;
};

